mapper.select:
SELECT 
FROM reservations
WHERE station_id = #{stationId}
AND status != 'cancelled' AND reserved_start_time < #{endTime}
AND reserved_end_time > #{startTime}

mapper.update:
UPDATE reservations
SET status = #{status}
WHERE reservation_id = #{reservationId}

mapper.insert:
INSERT INTO reservations (
    user_id, station_id, reserved_start_time, reserved_end_time, status, created_at
) VALUES (
             #{userId}, #{stationId}, #{reservedStartTime}, #{reservedEndTime}, #{status}, #{createdAt}
         )
